#!/usr/bin/perl
use strict;
use warnings;
use CGI;
use DBI;

my $cgi = CGI->new();
my $username = $cgi->param('username');
my $password = $cgi->param('password');

if (!$username || !$password) {
    print "Content-type: text/html\n\n";
    print "<h1>Login failed</h1>";
    exit;
}

my $dsn = 'DBI:mysql:database=mydb;host=localhost';
my $user = 'myuser';
my $pass = 'mypassword';

my $dbh = DBI->connect($dsn, $user, $pass) or die "Can't connect to database: $DBI::errstr";

my $sth = $dbh->prepare("SELECT * FROM users WHERE username=? AND password=?");
$sth->execute($username, $password);

if ($sth->rows > 0) {
    print "Content-type: text/html\n\n";
    print "<h1>Login successful</h1>";
} else {
    print "Content-type: text/html\n\n";
    print "<h1>Login failed</h1>";
}

$dbh->disconnect;